package cmd

import (
	"context"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"sort"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/docprose"
	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/spf13/cobra"
)

func (f *CommandFactory) newDocProseCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "prose [paths...]",
		Short: "Check prose quality in Markdown documents",
		Long: `Check prose quality in changed Markdown files or explicit paths.

The default surface is advisory. Findings are deterministic and
machine-readable, with file, line, rule id, severity, rationale, and
suggested edit fields.`,
		Args: cobra.ArbitraryArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			return f.runDocProse(cmd, args)
		},
	}
	cmd.Flags().Bool("changed", false, "Check changed Markdown files in the current git repo")
	return cmd
}

type proseSettings struct {
	Mode       docprose.Mode
	Severity   string
	Policy     string
	Runner     string
	Includes   []string
	Excludes   []string
	Vocabulary docprose.Vocabulary
}

func (f *CommandFactory) runDocProse(cmd *cobra.Command, args []string) error {
	changed, _ := cmd.Flags().GetBool("changed")

	cfg, err := config.LoadWithWorkingDir(f.docRoot())
	if err != nil {
		return err
	}

	settings, err := resolveProseSettings(cfg)
	if err != nil {
		return err
	}

	if err := maybeReportMissingRunner(cmd, settings.Runner); err != nil {
		return err
	}

	rootDir := f.docRoot()
	var relPaths []string
	if changed {
		if len(args) > 0 {
			return fmt.Errorf("use either --changed or explicit paths, not both")
		}
		relPaths, err = changedMarkdownPaths(rootDir)
		if err != nil {
			return err
		}
	} else {
		if len(args) == 0 {
			return fmt.Errorf("provide one or more paths or pass --changed")
		}
		relPaths = append([]string(nil), args...)
	}

	checker, err := docprose.NewChecker(settings.Mode, settings.Vocabulary)
	if err != nil {
		return err
	}

	var findings []docprose.Finding
	for _, relPath := range relPaths {
		cleanRel, absPath, ok := normalizeDocPath(rootDir, relPath)
		if !ok {
			continue
		}
		if !strings.EqualFold(filepath.Ext(cleanRel), ".md") {
			continue
		}
		if !pathAllowed(cleanRel, settings.Includes, settings.Excludes) {
			continue
		}
		content, readErr := os.ReadFile(absPath)
		if readErr != nil {
			if os.IsNotExist(readErr) {
				continue
			}
			return fmt.Errorf("read %s: %w", relPath, readErr)
		}
		for _, finding := range checker.Findings(cleanRel, string(content)) {
			if settings.Severity != "" {
				finding.Severity = settings.Severity
			}
			findings = append(findings, finding)
		}
	}

	sort.Slice(findings, func(i, j int) bool {
		if findings[i].File != findings[j].File {
			return findings[i].File < findings[j].File
		}
		if findings[i].Line != findings[j].Line {
			return findings[i].Line < findings[j].Line
		}
		return findings[i].RuleID < findings[j].RuleID
	})

	out := cmd.OutOrStdout()
	if len(findings) == 0 {
		if changed {
			fmt.Fprintln(out, "No changed Markdown prose findings.")
		} else {
			fmt.Fprintln(out, "No prose findings.")
		}
		return nil
	}

	for _, finding := range findings {
		fmt.Fprintf(out, "%s:%d [%s] %s\n", finding.File, finding.Line, finding.Severity, finding.RuleID)
		fmt.Fprintf(out, "  rationale: %s\n", finding.Rationale)
		fmt.Fprintf(out, "  suggested edit: %s\n", finding.SuggestedEdit)
	}

	if isBlockingProsePolicy(settings.Policy, settings.Severity) {
		cmd.SilenceUsage = true
		cmd.SilenceErrors = true
		return NewExitError(ExitCodeGeneralError, "")
	}
	return nil
}

func resolveProseSettings(cfg *config.Config) (proseSettings, error) {
	settings, err := docprose.DefaultSettings()
	if err != nil {
		return proseSettings{}, err
	}
	out := proseSettings{
		Mode:       settings.Mode,
		Severity:   settings.Severity,
		Policy:     settings.Policy,
		Runner:     settings.Runner,
		Includes:   append([]string(nil), settings.Includes...),
		Excludes:   append([]string(nil), settings.Excludes...),
		Vocabulary: settings.Vocabulary,
	}
	if cfg == nil || cfg.Prose == nil {
		return out, nil
	}

	if cfg.Prose.Mode != "" {
		out.Mode = docprose.Mode(cfg.Prose.Mode)
	}
	if cfg.Prose.Severity != "" {
		out.Severity = cfg.Prose.Severity
	}
	if cfg.Prose.Policy != "" {
		out.Policy = cfg.Prose.Policy
	}
	if cfg.Prose.Runner != "" {
		out.Runner = cfg.Prose.Runner
	}
	if len(cfg.Prose.Includes) > 0 {
		out.Includes = append([]string(nil), cfg.Prose.Includes...)
	}
	if len(cfg.Prose.Excludes) > 0 {
		out.Excludes = append([]string(nil), cfg.Prose.Excludes...)
	}
	if cfg.Prose.Vocabulary != nil {
		if len(cfg.Prose.Vocabulary.Accept) > 0 {
			out.Vocabulary.Accept = append([]string(nil), cfg.Prose.Vocabulary.Accept...)
		}
		if len(cfg.Prose.Vocabulary.Reject) > 0 {
			out.Vocabulary.Reject = append([]string(nil), cfg.Prose.Vocabulary.Reject...)
		}
	}

	return out, nil
}

func maybeReportMissingRunner(cmd *cobra.Command, runner string) error {
	runner = strings.TrimSpace(strings.ToLower(runner))
	switch runner {
	case "", "embedded":
		return nil
	case "auto", "vale":
		if _, err := exec.LookPath("vale"); err != nil {
			fmt.Fprintf(cmd.ErrOrStderr(), "warning: optional prose runner %q is unavailable; using embedded checker\n", "vale")
		}
		return nil
	default:
		return fmt.Errorf("unsupported prose runner %q", runner)
	}
}

func isBlockingProsePolicy(policy, severity string) bool {
	return strings.EqualFold(policy, "blocking") || strings.EqualFold(severity, "blocking")
}

func changedMarkdownPaths(rootDir string) ([]string, error) {
	out, err := internalgit.Command(context.Background(), rootDir, "status", "--porcelain=v1", "--untracked-files=all").Output()
	if err != nil {
		return nil, fmt.Errorf("git status failed: %w", err)
	}

	var paths []string
	for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
		if line == "" || len(line) < 3 {
			continue
		}
		status := line[:2]
		pathText := strings.TrimSpace(line[3:])
		if pathText == "" {
			continue
		}
		if strings.Contains(pathText, " -> ") {
			parts := strings.Split(pathText, " -> ")
			pathText = parts[len(parts)-1]
		}
		if strings.ContainsRune(status, 'D') {
			continue
		}
		if !strings.EqualFold(filepath.Ext(pathText), ".md") {
			continue
		}
		paths = append(paths, filepath.ToSlash(pathText))
	}
	sort.Strings(paths)
	return paths, nil
}

func normalizeDocPath(rootDir, input string) (string, string, bool) {
	if strings.TrimSpace(input) == "" {
		return "", "", false
	}
	absPath := input
	if !filepath.IsAbs(input) {
		absPath = filepath.Join(rootDir, input)
	}
	absPath = filepath.Clean(absPath)
	relPath, err := filepath.Rel(rootDir, absPath)
	if err != nil {
		relPath = filepath.ToSlash(filepath.Clean(input))
	} else {
		relPath = filepath.ToSlash(relPath)
	}
	return relPath, absPath, true
}

func pathAllowed(relPath string, includes, excludes []string) bool {
	relPath = filepath.ToSlash(relPath)
	if len(includes) > 0 && !anyGlobMatch(includes, relPath) {
		return false
	}
	if len(excludes) > 0 && anyGlobMatch(excludes, relPath) {
		return false
	}
	return true
}

func anyGlobMatch(patterns []string, relPath string) bool {
	for _, pattern := range patterns {
		if matchPathGlob(pattern, relPath) {
			return true
		}
	}
	return false

package docprose

import (
	"fmt"
	"regexp"
	"strings"
	"unicode"
)

type Mode string

const (
	ModeTechnical Mode = "technical"
	ModePlanning  Mode = "planning"
	ModePublic    Mode = "public"
)

type Checker struct {
	mode       Mode
	rules      []ruleSpec
	vocabulary Vocabulary
}

func NewChecker(mode Mode, vocabulary Vocabulary) (*Checker, error) {
	if mode == "" {
		mode = ModeTechnical
	}
	rules, err := loadRulePack(string(mode))
	if err != nil {
		return nil, err
	}
	defaultVocab, err := loadDefaultVocabulary()
	if err != nil {
		return nil, err
	}
	if len(vocabulary.Accept) == 0 {
		vocabulary.Accept = defaultVocab.Accept
	}
	if len(vocabulary.Reject) == 0 {
		vocabulary.Reject = defaultVocab.Reject
	}
	return &Checker{
		mode:       mode,
		rules:      rules,
		vocabulary: vocabulary,
	}, nil
}

func (c *Checker) Findings(file, text string) []Finding {
	var findings []Finding
	lines := strings.Split(text, "\n")

	for idx, raw := range lines {
		lineNo := idx + 1
		line := strings.TrimSpace(raw)
		if line == "" {
			continue
		}

		for _, rule := range c.rules {
			if rule.Kind == "repeated_opening" {
				if repeatedOpeningKey(line) != "" {
					findings = append(findings, Finding{
						File:          file,
						Line:          lineNo,
						RuleID:        rule.ID,
						Severity:      rule.Severity,
						Rationale:     rule.Rationale,
						SuggestedEdit: rule.SuggestedEdit,
					})
				}
				continue
			}
			if matchesRule(line, rule) {
				findings = append(findings, Finding{
					File:          file,
					Line:          lineNo,
					RuleID:        rule.ID,
					Severity:      rule.Severity,
					Rationale:     rule.Rationale,
					SuggestedEdit: rule.SuggestedEdit,
				})
			}
		}

		findings = append(findings, c.vocabularyFindings(file, lineNo, line)...)
	}

	return findings
}

func (c *Checker) vocabularyFindings(file string, lineNo int, line string) []Finding {
	var findings []Finding
	lower := strings.ToLower(line)
	for _, reject := range c.vocabulary.Reject {
		if reject == "" {
			continue
		}
		if !containsWord(lower, reject) {
			continue
		}
		if c.termAccepted(reject) {
			continue
		}
		findings = append(findings, Finding{
			File:          file,
			Line:          lineNo,
			RuleID:        "prose.vocabulary.reject",
			Severity:      "warning",
			Rationale:     fmt.Sprintf("The vocabulary term %q is discouraged in default prose because it is too generic.", reject),
			SuggestedEdit: fmt.Sprintf("Replace %q with the project-specific term or concrete noun that names the actual concept.", reject),
		})
	}
	return findings
}

func (c *Checker) termAccepted(term string) bool {
	for _, accept := range c.vocabulary.Accept {
		if accept == "" {
			continue
		}
		if strings.EqualFold(strings.TrimSpace(accept), strings.TrimSpace(term)) {
			return true
		}
	}
	return false
}

func matchesRule(line string, rule ruleSpec) bool {
	if len(rule.ContainsAny) == 0 {
		return false
	}
	lower := strings.ToLower(line)
	for _, phrase := range rule.ContainsAny {
		if phrase == "" {
			continue
		}
		if strings.Contains(lower, strings.ToLower(phrase)) {
			return true
		}
	}
	return false
}

func repeatedOpeningKey(line string) string {
	first, rest, ok := cutSentence(line)
	if !ok {
		return ""
	}
	second, _, ok := cutSentence(rest)
	if !ok {
		return ""
	}
	first = normalizeSentence(first)
	second = normalizeSentence(second)
	if first == "" || first != second {
		return ""
	}
	return first
}

func cutSentence(s string) (head, tail string, ok bool) {
	s = strings.TrimSpace(s)
	if s == "" {
		return "", "", false
	}
	for i, r := range s {
		if r == '.' || r == '!' || r == '?' {
			return strings.TrimSpace(s[:i+1]), strings.TrimSpace(s[i+1:]), true
		}
	}
	return "", "", false
}

func normalizeSentence(s string) string {
	s = strings.ToLower(strings.TrimSpace(s))
	s = strings.TrimFunc(s, func(r rune) bool {
		return unicode.IsPunct(r) || unicode.IsSpace(r)
	})
	s = strings.Join(strings.Fields(s), " ")
	return s
}

func containsWord(haystack, needle string) bool {
	needle = strings.TrimSpace(needle)
	if needle == "" {
		return false
	}
	pattern := `(?i)(^|[^[:alnum:]_])` + regexp.QuoteMeta(needle) + `([^[:alnum:]_]|$)`
	return regexp.MustCompile(pattern).FindStringIndex(haystack) != nil
}

package docprose

import (
	"os"
	"path/filepath"
	"strings"
	"testing"
)

func TestProseCheckerFindingSchema(t *testing.T) {
	checker, err := NewChecker(ModeTechnical, Vocabulary{})
	if err != nil {
		t.Fatal(err)
	}
	findings := checker.Findings("input.md", "This is robust.\n")
	if len(findings) == 0 {
		t.Fatal("expected at least one finding")
	}
	f := findings[0]
	if f.File != "input.md" || f.Line != 1 || f.RuleID == "" || f.Severity == "" || f.Rationale == "" || f.SuggestedEdit == "" {
		t.Fatalf("finding missing required field(s): %+v", f)
	}
}

func TestProseCheckerVocabularyOverrides(t *testing.T) {
	checker, err := NewChecker(ModeTechnical, Vocabulary{
		Accept: []string{"Quartz"},
		Reject: []string{"system", "solution"},
	})
	if err != nil {
		t.Fatal(err)
	}

	findings := checker.Findings("input.md", "Quartz keeps the system solution honest.\n")
	if len(findings) != 2 {
		t.Fatalf("expected 2 reject findings, got %+v", findings)
	}
	for _, finding := range findings {
		if finding.RuleID != "prose.vocabulary.reject" {
			t.Fatalf("unexpected rule id: %+v", finding)
		}
	}
}

func TestProseCheckerVocabularyPreservation(t *testing.T) {
	checker, err := NewChecker(ModeTechnical, Vocabulary{
		Accept: []string{"Quartz"},
		Reject: []string{"system"},
	})
	if err != nil {
		t.Fatal(err)
	}

	findings := checker.Findings("input.md", "Quartz keeps the system honest.\n")
	if len(findings) != 1 {
		t.Fatalf("expected one reject finding, got %+v", findings)
	}
	if findings[0].RuleID != "prose.vocabulary.reject" {
		t.Fatalf("unexpected rule id: %+v", findings[0])
	}
	if strings.Contains(findings[0].Rationale, "Quartz") {
		t.Fatalf("accepted term should not be flagged, got %+v", findings[0])
	}
}

func TestDefaultAssetLayout(t *testing.T) {
	root, err := defaultAssetRoot()
	if err != nil {
		t.Fatal(err)
	}
	for _, path := range []string{
		filepath.Join(root, "check.yaml"),
		filepath.Join(root, "rules", "technical.yaml"),
		filepath.Join(root, "rules", "planning.yaml"),
		filepath.Join(root, "rules", "public.yaml"),
		filepath.Join(root, "vocabulary", "default.yaml"),
	} {
		if _, err := os.Stat(path); err != nil {
			t.Fatalf("expected asset %s: %v", path, err)
		}
	}

	cfg, err := loadDefaultConfig()
	if err != nil {
		t.Fatal(err)
	}
	if cfg.Mode != string(ModeTechnical) || cfg.Policy != "advisory" || cfg.Runner != "embedded" {
		t.Fatalf("unexpected default config: %+v", cfg)
	}

	vocab, err := loadDefaultVocabulary()
	if err != nil {
		t.Fatal(err)
	}
	if !containsAll(vocab.Accept, []string{"DDx", "bead", "execution"}) {
		t.Fatalf("default accept vocabulary missing DDx terms: %+v", vocab.Accept)
	}
	if !containsAll(vocab.Reject, []string{"solution", "process"}) {
		t.Fatalf("default reject vocabulary missing generic terms: %+v", vocab.Reject)
	}
}

func TestProseCheckerChangedMode(t *testing.T) {
	cases := listFixtureCases(t, "testdata/fixtures")
	for _, tc := range cases {
		t.Run(tc.Mode+"/"+tc.Name, func(t *testing.T) {
			checker, err := NewChecker(Mode(tc.Mode), Vocabulary{})
			if err != nil {
				t.Fatal(err)
			}
			got := checker.Findings("input.md", tc.Input)
			if !sameFindings(got, tc.Findings) {
				t.Fatalf("fixture mismatch for %s/%s\n--- got ---\n%v\n--- want ---\n%v", tc.Mode, tc.Name, got, tc.Findings)
			}
		})
	}
}

func TestProseCheckerPathMode(t *testing.T) {
	checker, err := NewChecker(ModeTechnical, Vocabulary{})
	if err != nil {
		t.Fatal(err)
	}
	input := strings.Join([]string{
		"## Technical Context",
		"",
		"This is robust and comprehensive.",
	}, "\n")
	findings := checker.Findings("docs/helix/example.md", input)
	if len(findings) != 1 {
		t.Fatalf("expected one finding, got %+v", findings)
	}
	if findings[0].File != "docs/helix/example.md" {
		t.Fatalf("unexpected file in finding: %+v", findings[0])
	}
}

func sameFindings(got, want []Finding) bool {
	if len(got) != len(want) {
		return false
	}
	for i := range got {
		if got[i] != want[i] {
			return false
		}
	}
	return true
}

func containsAll(got []string, want []string) bool {
	m := make(map[string]bool, len(got))
	for _, s := range got {
		m[s] = true
	}
	for _, s := range want {
		if !m[s] {
			return false
		}
	}
	return true
}

package config

import (
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/triage"
)

// NewConfig represents the simplified DDx configuration structure
// This aligns with the schema defined in ADR-005 and SD-003
type NewConfig struct {
	Version         string              `yaml:"version" json:"version"`
	Library         *LibraryConfig      `yaml:"library" json:"library"`
	Bead            *BeadConfig         `yaml:"bead,omitempty" json:"bead,omitempty"`
	BeadQuality     *BeadQualityConfig  `yaml:"bead-quality,omitempty" json:"bead-quality,omitempty"`
	System          *SystemConfig       `yaml:"system,omitempty" json:"system,omitempty"`
	PersonaBindings map[string]string   `yaml:"persona_bindings,omitempty" json:"persona_bindings,omitempty"`
	UpdateCheck     *UpdateCheckConfig  `yaml:"update_check,omitempty" json:"update_check,omitempty"`
	Agent           *AgentConfig        `yaml:"agent,omitempty" json:"agent,omitempty"`
	Git             *GitConfig          `yaml:"git,omitempty" json:"git,omitempty"`
	Server          *ServerConfig       `yaml:"server,omitempty" json:"server,omitempty"`
	Executions      *ExecutionsConfig   `yaml:"executions,omitempty" json:"executions,omitempty"`
	Cost            *CostConfig         `yaml:"cost,omitempty" json:"cost,omitempty"`
	Workers         *WorkersConfig      `yaml:"workers,omitempty" json:"workers,omitempty"`
	EvidenceCaps    *EvidenceCapsConfig `yaml:"evidence_caps,omitempty" json:"evidence_caps,omitempty"`
	Prose           *ProseConfig        `yaml:"prose,omitempty" json:"prose,omitempty"`
	// ReviewMaxRetries caps reviewer attempts per committed result_rev before
	// the execute-loop emits a terminal `review-manual-required` event and
	// parks the bead (FEAT-022 §14). Zero or unset uses the binary default
	// (3). Negative values are treated as unset.
	ReviewMaxRetries *int `yaml:"review_max_retries,omitempty" json:"review_max_retries,omitempty"`
	// Triage configures the post-attempt triage decision module
	// (cli/internal/triage). Optional; when unset the binary default policy
	// is used. Distinct from agent.triage, which controls the pre-claim
	// complexity gate.
	Triage *TriagePolicyConfig `yaml:"triage,omitempty" json:"triage,omitempty"`
}

// TriagePolicyConfig is the project-config form of triage.TriagePolicy.
// Each entry of `policies` maps a failure mode name to an ordered ladder
// of action names; missing modes inherit the binary default ladder.
type TriagePolicyConfig struct {
	Policies map[string][]string `yaml:"policies,omitempty" json:"policies,omitempty"`
}

// BeadQualityConfig controls bead quality gates that run before dispatch.
type BeadQualityConfig struct {
	Lint *BeadQualityLintConfig `yaml:"lint,omitempty" json:"lint,omitempty"`
}

// BeadQualityLintConfig controls the pre-dispatch lint threshold behavior.
type BeadQualityLintConfig struct {
	// BlockThresholdScore, when positive, blocks dispatch for valid lint
	// results whose score falls below the threshold. Zero or unset keeps the
	// default warn-only behavior.
	BlockThresholdScore *int `yaml:"block_threshold_score,omitempty" json:"block_threshold_score,omitempty"`
}

// ProseConfig controls the deterministic prose-quality workflow.
type ProseConfig struct {
	Mode       string                 `yaml:"mode,omitempty" json:"mode,omitempty"`
	Severity   string                 `yaml:"severity,omitempty" json:"severity,omitempty"`
	Policy     string                 `yaml:"policy,omitempty" json:"policy,omitempty"`
	Runner     string                 `yaml:"runner,omitempty" json:"runner,omitempty"`
	Includes   []string               `yaml:"includes,omitempty" json:"includes,omitempty"`
	Excludes   []string               `yaml:"excludes,omitempty" json:"excludes,omitempty"`
	Vocabulary *ProseVocabularyConfig `yaml:"vocabulary,omitempty" json:"vocabulary,omitempty"`
}

// ProseVocabularyConfig configures project terms to preserve or reject.
type ProseVocabularyConfig struct {
	Accept []string `yaml:"accept,omitempty" json:"accept,omitempty"`
	Reject []string `yaml:"reject,omitempty" json:"reject,omitempty"`
}

// ResolveTriagePolicy returns the effective triage policy for this config,
// layering any `triage.policies` entries on top of the binary default
// ladders. Unknown failure-mode names and unknown action names are
// silently dropped (schema validation surfaces typos at load time).
func (c *NewConfig) ResolveTriagePolicy() triage.TriagePolicy {
	policy := triage.DefaultPolicy()
	if c == nil || c.Triage == nil || len(c.Triage.Policies) == 0 {
		return policy
	}
	for modeStr, actionStrs := range c.Triage.Policies {
		mode, err := triage.ParseFailureMode(modeStr)
		if err != nil {
			continue
		}
		ladder := make([]triage.Action, 0, len(actionStrs))
		for _, a := range actionStrs {
			act, err := triage.ParseAction(a)
			if err != nil {
				continue
			}
			ladder = append(ladder, act)
		}
		if len(ladder) == 0 {
			continue
		}
		policy.Ladders[mode] = ladder
	}
	return policy
}

// ResolveBeadQualityLintBlockThresholdScore returns the effective lint block
// threshold. Defaults to 0, which means warn-only.
func (c *NewConfig) ResolveBeadQualityLintBlockThresholdScore() int {
	if c == nil || c.BeadQuality == nil || c.BeadQuality.Lint == nil || c.BeadQuality.Lint.BlockThresholdScore == nil {
		return 0
	}
	if *c.BeadQuality.Lint.BlockThresholdScore <= 0 {
		return 0
	}
	return *c.BeadQuality.Lint.BlockThresholdScore
}

// ResolveReviewMaxRetries returns the effective reviewer retry cap for this
// config. Defaults to 3 when unset (matching agent.DefaultReviewMaxRetries).
